class Solution:
    def getMoneyAmount(self, n):
        from functools import lru_cache
        import sys
        sys.setrecursionlimit(100000)
        @lru_cache(maxsize=None)
        def solve(lo, hi):
            if lo >= hi:
                return 0
            best = float('inf')
            for k in range(lo, hi + 1):
                cost = k + max(solve(lo, k - 1), solve(k + 1, hi))
                if cost < best:
                    best = cost
            return best
        return solve(1, n)

