class Solution:
    def getMoneyAmount(self, n):
        dp = [[0] * (n + 2) for _ in range(n + 2)]
        for length in range(2, n + 1):
            for lo in range(1, n - length + 2):
                hi = lo + length - 1
                best = float('inf')
                for k in range(lo, hi + 1):
                    left = dp[lo][k - 1] if k - 1 >= lo else 0
                    right = dp[k + 1][hi] if k + 1 <= hi else 0
                    cost = k + max(left, right)
                    if cost < best:
                        best = cost
                dp[lo][hi] = best
        return dp[1][n]

